34	    num_err++;
35	  }
36	  /* Try to match the programming clock port name with the CCFF port name */
37	  for (BasicPort prog_clk_port : config_protocol.prog_clock_pins()) {
38	    bool port_match = false;
39	    for (CircuitModelId ccff_model : ccff_models) {
40	      CircuitPortId circuit_port =
41	        circuit_lib.model_port(ccff_model, prog_clk_port.get_name());
42	      if (circuit_port) {
43	        port_match = true;
44	        /* Ensure this is a programming clock and a global port */
45	        if (!circuit_lib.port_is_global(circuit_port)) {
46	          VTR_LOG_ERROR(
47	            "Expect the programming clock '%s' to be a global port but not!\n",
48	            prog_clk_port.get_name().c_str());
49	          num_err++;
50	        }
51	        if (circuit_lib.port_type(circuit_port) != CIRCUIT_MODEL_PORT_CLOCK) {
52	          VTR_LOG_ERROR(
53	            "Expect the programming clock '%s' to be a clock port but not!\n",
54	            prog_clk_port.get_name().c_str());
55	          num_err++;
56	        }
57	        if (!circuit_lib.port_is_prog(circuit_port)) {
58	          VTR_LOG_ERROR(
59	            "Expect the programming clock '%s' to be a programming port but "
60	            "not!\n",
61	            prog_clk_port.get_name().c_str());
62	          num_err++;
63	        }
64	      }
65	    }
66	    if (!port_match) {
67	      VTR_LOG_ERROR(
68	        "Fail to find a port of any CCFF model that matches the programming "
69	        "clock definition (Expect port name: '%s')!\n",
70	        prog_clk_port.get_name().c_str());
71	      num_err++;
72	    }
73	  }
74	
75	  return num_err;
76	}
77	
78	/********************************************************************
79	 * Check if the configuration protocol is valid without any conflict with
80	 * circuit library content.
81	 *******************************************************************/
82	bool check_config_protocol(const ConfigProtocol& config_protocol,
83	                           const CircuitLibrary& circuit_lib) {
84	  int num_err = 0;
85	
86	  if (0 < config_protocol.validate()) {
87	    num_err++;
