143	/********************************************************************
144	 * Parse XML codes of a <organization> to an object of configuration protocol
145	 *******************************************************************/
146	static void read_xml_config_organization(pugi::xml_node& xml_config_orgz,
147	                                         const pugiutil::loc_data& loc_data,
148	                                         ConfigProtocol& config_protocol) {
149	  /* Find the type of configuration protocol */
150	  const char* type_attr =
151	    get_attribute(xml_config_orgz, "type", loc_data).value();
152	  /* Translate the type of design technology to enumerate */
153	  e_config_protocol_type config_orgz_type =
154	    string_to_config_protocol_type(std::string(type_attr));
155	
156	  if (NUM_CONFIG_PROTOCOL_TYPES == config_orgz_type) {
157	    archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_config_orgz),
158	                   "Invalid 'type' attribute '%s'\n", type_attr);
159	  }
160	
161	  config_protocol.set_type(config_orgz_type);
162	
163	  /* Find the circuit model used by the configuration protocol */
164	  config_protocol.set_memory_model_name(
165	    get_attribute(xml_config_orgz, "circuit_model_name", loc_data).as_string());
166	
167	  /* Parse the number of configurable regions
168	   * At least 1 region should be defined, otherwise error out
169	   */
170	  config_protocol.set_num_regions(
171	    get_attribute(xml_config_orgz, XML_CONFIG_PROTOCOL_NUM_REGIONS_ATTR,
172	                  loc_data, pugiutil::ReqOpt::OPTIONAL)
173	      .as_int(1));
174	  if (1 > config_protocol.num_regions()) {
175	    archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_config_orgz),
176	                   "Invalid 'num_region=%d' definition. At least 1 region "
177	                   "should be defined!\n",
178	                   config_protocol.num_regions());
179	  }
180	
181	  /* Parse Configuration chain protocols */
182	  if (config_protocol.type() == CONFIG_MEM_SCAN_CHAIN) {
183	    /* First pass: Get the programming clock port size */
184	    openfpga::BasicPort prog_clk_port;
185	    for (pugi::xml_node xml_progclk : xml_config_orgz.children()) {
186	      /* Error out if the XML child has an invalid name! */
187	      if (xml_progclk.name() !=
188	          std::string(XML_CONFIG_PROTOCOL_CCFF_PROG_CLOCK_NODE_NAME)) {
189	        bad_tag(xml_progclk, loc_data, xml_config_orgz,
190	                {XML_CONFIG_PROTOCOL_CCFF_PROG_CLOCK_NODE_NAME});
191	      }
192	      std::string port_attr =
193	        get_attribute(xml_progclk,
194	                      XML_CONFIG_PROTOCOL_CCFF_PROG_CLOCK_PORT_ATTR, loc_data)
195	          .as_string();
196	      openfpga::BasicPort port = openfpga::PortParser(port_attr).port();
197	      if (prog_clk_port.get_name().empty()) {
198	        prog_clk_port.set_name(port.get_name());
199	        prog_clk_port.set_width(port.get_lsb(), port.get_msb());
200	      } else {
201	        if (prog_clk_port.get_name() != port.get_name()) {
202	          archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_progclk),
203	                         "Expect same name for all the programming clocks "
204	                         "(This: %s, Others: %s)!\n",
205	                         port.get_name().c_str(),
206	                         prog_clk_port.get_name().c_str());
207	        }
208	        if (prog_clk_port.get_msb() < port.get_msb()) {
209	          prog_clk_port.set_msb(port.get_msb());
210	        }
211	      }
212	    }
213	    config_protocol.set_prog_clock_port(prog_clk_port);
214	
215	    /* Second pass: fill the clock detailed connections */
216	    for (pugi::xml_node xml_progclk : xml_config_orgz.children()) {
217	      /* Error out if the XML child has an invalid name! */
218	      if (xml_progclk.name() !=
219	          std::string(XML_CONFIG_PROTOCOL_CCFF_PROG_CLOCK_NODE_NAME)) {
220	        bad_tag(xml_progclk, loc_data, xml_config_orgz,
221	                {XML_CONFIG_PROTOCOL_CCFF_PROG_CLOCK_NODE_NAME});
222	      }
223	      read_xml_ccff_prog_clock(xml_progclk, loc_data, config_protocol);
224	    }
225	  }
226	
227	  /* Parse BL & WL protocols */
228	  if (config_protocol.type() == CONFIG_MEM_QL_MEMORY_BANK) {
229	    pugi::xml_node xml_bl_protocol = get_single_child(
230	      xml_config_orgz, "bl", loc_data, pugiutil::ReqOpt::OPTIONAL);
231	    if (xml_bl_protocol) {
232	      read_xml_bl_protocol(xml_bl_protocol, loc_data, config_protocol);
233	    }
234	
235	    pugi::xml_node xml_wl_protocol = get_single_child(
236	      xml_config_orgz, "wl", loc_data, pugiutil::ReqOpt::OPTIONAL);
237	    if (xml_wl_protocol) {
238	      read_xml_wl_protocol(xml_wl_protocol, loc_data, config_protocol);
239	    }
240	
241	    /* Throw an execption if the BL/WL protocols are different. We currently do
242	     * not support it! */
243	    if (config_protocol.bl_protocol_type() !=
244	        config_protocol.wl_protocol_type()) {
245	      archfpga_throw(loc_data.filename_c_str(), loc_data.line(xml_config_orgz),
246	                     "Expect same type of protocol for both BL and WL! Other "
247	                     "combinations are not supported yet\n");
248	    }
249	  }
250	}
251	
252	/********************************************************************
253	 * Parse XML codes about <ql_memory_bank_config_setting> to
254	 *QLMemoryBankConfigSetting
255	 *******************************************************************/
256	static void read_xml_ql_memory_bank_config_setting(
257	  QLMemoryBankConfigSetting* setting, pugi::xml_node& Node,
258	  const pugiutil::loc_data& loc_data) {
259	  /* Parse configuration protocol root node */
260	  pugi::xml_node config_setting =
261	    get_single_child(Node, "ql_memory_bank_config_setting", loc_data,
262	                     pugiutil::ReqOpt::OPTIONAL);
263	
264	  if (config_setting) {
265	    /* Add to ql_memory_bank_config_setting_ */
266	    for (pugi::xml_node xml_child : config_setting.children()) {
267	      if (xml_child.name() != std::string("pb_type")) {
268	        bad_tag(xml_child, loc_data, config_setting, {"pb_type"});
269	      }
270	      const std::string& name_attr =
271	        get_attribute(xml_child, "name", loc_data).as_string();
272	      uint32_t num_wl = get_attribute(xml_child, "num_wl", loc_data).as_uint();
273	      setting->add_pb_setting(name_attr, num_wl);
274	    }
275	  }
276	}
277	
278	/********************************************************************
279	 * Parse XML codes about <configuration_protocol> to an object of ConfigProtocol
280	 *******************************************************************/
281	ConfigProtocol read_xml_config_protocol(pugi::xml_node& Node,
282	                                        const pugiutil::loc_data& loc_data) {
283	  ConfigProtocol config_protocol;
284	
285	  /* Parse configuration protocol root node */
286	  pugi::xml_node xml_config =
287	    get_single_child(Node, "configuration_protocol", loc_data);
288	
289	  pugi::xml_node xml_config_orgz =
290	    get_single_child(xml_config, "organization", loc_data);
291	  read_xml_config_organization(xml_config_orgz, loc_data, config_protocol);
292	
293	  /* Parse QL Memory Bank configuration setting */
294	  if (config_protocol.type() == CONFIG_MEM_QL_MEMORY_BANK &&
295	      config_protocol.bl_protocol_type() == BLWL_PROTOCOL_FLATTEN &&
296	      config_protocol.wl_protocol_type() == BLWL_PROTOCOL_FLATTEN) {
297	    read_xml_ql_memory_bank_config_setting(
298	      config_protocol.get_ql_memory_bank_config_setting(), xml_config,
299	      loc_data);
300	  }
301	
302	  return config_protocol;
303	}
