268	/************************************************************************
269	 * Private Validators
270	 ***********************************************************************/
271	int ConfigProtocol::validate_ccff_prog_clocks() const {
272	  int num_err = 0;
273	  if (prog_clock_pins().empty()) {
274	    return num_err;
275	  }
276	  /* Initialize scoreboard */
277	  std::vector<int> ccff_head_scoreboard(num_regions(), 0);
278	  for (openfpga::BasicPort port : prog_clock_pins()) {
279	    /* Must be valid first */
280	    if (!port.is_valid()) {
281	      VTR_LOG_ERROR("Programming clock '%s[%d:%d]' is not a valid port!\n",
282	                    port.get_name().c_str(), port.get_lsb(), port.get_msb());
283	      num_err++;
284	    }
285	    /* Each port should have a width of 1 */
286	    if (port.get_width() != 1) {
287	      VTR_LOG_ERROR(
288	        "Expect each programming clock has a size of 1 in the definition. "
289	        "'%s[%d:%d]' violates the rule!\n",
290	        port.get_name().c_str(), port.get_lsb(), port.get_msb());
291	      num_err++;
292	    }
293	    /* Fill scoreboard */
294	    for (size_t ccff_head_idx : prog_clock_pin_ccff_head_indices(port)) {
295	      if (ccff_head_idx >= ccff_head_scoreboard.size()) {
296	        VTR_LOG_ERROR(
297	          "Programming clock '%s[%d:%d]' controlls an invalid ccff head '%ld' "
298	          "(Expect [0, '%ld'])!\n",
299	          port.get_name().c_str(), port.get_lsb(), port.get_msb(),
300	          ccff_head_idx, ccff_head_scoreboard.size() - 1);
301	        num_err++;
302	      }
303	      ccff_head_scoreboard[ccff_head_idx]++;
304	    }
305	  }
306	  if (prog_clock_pins().size() > (size_t)num_regions()) {
307	    VTR_LOG_ERROR(
308	      "Number of programming clocks '%ld' is more than the number of "
309	      "configuration regions '%ld'!\n",
310	      prog_clock_pins().size(), num_regions());
311	    num_err++;
312	  }
313	  for (size_t iregion = 0; iregion < ccff_head_scoreboard.size(); iregion++) {
314	    if (ccff_head_scoreboard[iregion] == 0) {
315	      VTR_LOG_ERROR(
316	        "Configuration chain '%ld' is not driven by any programming clock!\n",
317	        iregion);
318	      num_err++;
319	    }
320	    if (ccff_head_scoreboard[iregion] > 1) {
321	      VTR_LOG_ERROR(
322	        "Configuration chain '%ld' is driven by %ld programming clock!\n",
323	        iregion, ccff_head_scoreboard[iregion]);
324	      num_err++;
325	    }
326	  }
327	  return num_err;
328	}
329	
330	/************************************************************************
331	 * Public Validators
332	 ***********************************************************************/
333	int ConfigProtocol::validate() const {
334	  int num_err = 0;
335	  if (type() == CONFIG_MEM_SCAN_CHAIN) {
336	    num_err += validate_ccff_prog_clocks();
337	  }
338	  return num_err;
339	}
