366	/************************************************************************
367	 * Try to find the enable port control power-gate for a power-gated circuit
368	 *model We will return the first port that meet the requirement:
369	 * - a global port
370	 * - its function is labelled as config_enable
371	 * - default value is 0
372	 * Return invalid id if not found
373	 ***********************************************************************/
374	CircuitPortId find_circuit_model_power_gate_en_port(
375	  const CircuitLibrary& circuit_lib, const CircuitModelId& circuit_model) {
376	  VTR_ASSERT(true == circuit_lib.is_power_gated(circuit_model));
377	  std::vector<CircuitPortId> global_ports =
378	    circuit_lib.model_global_ports_by_type(
379	      circuit_model, CIRCUIT_MODEL_PORT_INPUT, true, true);
380	
381	  /* Try to find an ENABLE port from the global ports */
